// Enrich game data with player-perspective context
// Determines color played, ratings, result, and opening code

const game = $input.item.json;
const reviewingUsername = game._username;

const playedWhite = game.white.username.toLowerCase() === reviewingUsername.toLowerCase();

const playerColor    = playedWhite ? 'White' : 'Black';
const opponentColor  = playedWhite ? 'Black' : 'White';
const playerData     = playedWhite ? game.white : game.black;
const opponentData   = playedWhite ? game.black : game.white;

// Map result codes to human-readable outcomes
const WIN_CODES  = ['win'];
const LOSS_CODES = ['resigned', 'checkmated', 'timeout', 'abandoned'];
const DRAW_CODES = ['agreed', 'stalemate', 'repetition', 'insufficient', '50move', 'timevsinsufficient'];

let gameResult = 'Unknown';
let resultEmoji = '❓';

if (WIN_CODES.includes(playerData.result)) {
  gameResult = 'Win';  resultEmoji = '🏆';
} else if (LOSS_CODES.includes(playerData.result)) {
  gameResult = 'Loss'; resultEmoji = '💔';
} else if (DRAW_CODES.includes(playerData.result)) {
  gameResult = 'Draw'; resultEmoji = '🤝';
}

// Extract ECO opening code from the eco URL field
let ecoCode = 'Unknown';
if (game.eco) {
  const ecoMatch = game.eco.match(/\/([A-E]\d{2})/);
  if (ecoMatch) ecoCode = ecoMatch[1];
}

return {
  json: {
    ...game,
    reviewingUsername,
    playerColor,
    opponentColor,
    playerRating:    playerData.rating,
    opponentUsername: opponentData.username,
    opponentRating:  opponentData.rating,
    gameResult,
    resultEmoji,
    playerResult:   playerData.result,
    opponentResult: opponentData.result,
    ecoCode
  }
};

// Sort all games by end time, newest first
// Then output as individual items for the batch processor
const games = $input.item.json.games;
const username = $("Config  - Username - Email").first().json.username;

if (!games || games.length === 0) {
  throw new Error(`No games found this month for player: ${username}`);
}

// Sort descending by end_time (most recent game first)
games.sort((a, b) => b.end_time - a.end_time);

// Attach the reviewing username to each game for downstream use
return games.map(game => ({
  json: {
    ...game,
    _username: username
  }
}));

// Build the Chess.com API URL for the current month's games
const username = $input.item.json.username;

const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');

// Chess.com public API endpoint for monthly games
const url = `https://api.chess.com/pub/player/${username}/games/${year}/${month}`;

return [
  {
    json: {
      username: username,
      year: year,
      month: month,
      url: url
    }
  }
];
